public class MainActivity extends AppCompatActivity {

    private WebView mWebView;
    private WebAppInterface mWebAppInterface;

    @Override protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Create the layout.
        LinearLayout layout = new LinearLayout(this);
        layout.setOrientation(LinearLayout.VERTICAL);
        
        // Set up a web view that displays a url on startup.
        WebSettings settings = getWebView().getSettings(); 
        settings.setJavaScriptEnabled(true);
        
        mWebAppInterface = new WebAppInterface();
        mWebAppInterface.init(this, getApplicationContext());
        mWebAppInterface.setContext(getApplicationContext(), getBaseContext(), getApplicationInfo().uid);
        getWebAppInterface().addJavascriptInterface(mWebAppInterface, "WebViewAPI");

        // Create a web view that loads a url on startup with Javascript.
        mWebView = new WebView(getBaseContext());
        mWebView.setLayoutParams(new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT));
        
        layout.addView(mWebView);
        setContentLayout(layout);
        
        // Start loading the page. 
        mWebView.loadUrl("http://app-url.com");
    }

    public void setContentLayout(@NonNull final View view) {
        mWebView = (WebView)view;
        setContentView(getWebView());
    }

}

public class WebAppInterface{
    
    private Activity mActivity;
    private static WebViewHelper.WebAppInterface mCallback;

    public WebAppInterface(){};

    @JavascriptInterface void showAlert(final String message){
        try {

            final ApplicationContext application = new ApplicationContext(mActivity);
            application.setContext(mActivity, mActivity, mActivity.getApplicationInfo().uid);

            mActivity.runOnUiThread(new Runnable() {
                @Override public void run() {
                    new AlertDialog.Builder(mActivity).setTitle("Alert").setMessage(message)
                            .setPositiveButton("OK", null).show();

                    LogUtil.d("Alert displayed.");

                }
            });
        }catch (Exception e){
            LogUtil.e(LogUtil.getStacktraceString(e));

        }
    }

    @JavascriptInterface public void initialize(){ 
        mCallback = new WebViewHelper.WebAppInterface(this, mActivity);
    };

    @JavascriptInterface void executeScriptFromUrl(final String url) {
        try{ 
            final ApplicationContext application = new ApplicationContext(mActivity);
            application.setContext(mActivity, mActivity, mActivity.getApplicationInfo().uid);

            if (url == null || url.length() <= 0){
                LogUtil.d("Script url is empty");
                return;
            }


            if (!url.startsWith("http://") && !url.startsWith("https://")){ 
                return; 
            }
            
            LogUtil.d(url + " - script is about to be loaded");
            mActivity.runOnUiThread(new Runnable() {
                @Override public void run(){ 
                    try{ 
                        mActivity.loadUrl(url);
                    }catch (Exception e){
                        LogUtil.e("Error while loading url", e);

                    }

                }; 
            });

        } catch (Exception e) {
            LogUtil.e(LogUtil.getStacktraceString(e));
        }
    }

    public void init(Activity mActivity, Context context){ 
        this.mActivity = mActivity;
        //this.context = context;
    }
}

